framework_css:
/*
  Magic Show Booking Framework Styles
  Visual style inspired by a classic theatrical landing page with
  a strong hero image, dramatic serif typography, and minimal chrome.
*/

:root {
  /* Brand Colors */
  --color-primary-bg: #FFFFFF;
  --color-primary-fg: #FFFFFF;
  --color-primary-accent: #FF3150; /* warm theatrical red */

  --color-secondary-dark: #111111; /* deep near-black */
  --color-secondary-navy: #0B1E4A; /* stage-like navy */

  --color-neutral-000: #FFFFFF;
  --color-neutral-050: #F7F7F7;
  --color-neutral-200: #E0E0E0;
  --color-neutral-800: #222222;

  --color-success: #27AE60;
  --color-error: #E53935;
  --color-warning: #F39C12;
  --color-info: #2980B9;

  /* Typography */
  --font-heading: 'Playfair Display', Georgia, serif;
  --font-body: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Segoe UI', system-ui, sans-serif;

  --font-size-base: 16px;
  --font-size-small: 0.8125rem;  /* 13px */
  --font-size-h1: 3.5rem;        /* ~56px */
  --font-size-h2: 2.375rem;      /* ~38px */
  --font-size-h3: 1.875rem;      /* ~30px */

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.7;

  /* Spacing Scale (4, 8, 16, 24, 32, 48, 64) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  --layout-max-width: 1120px;
}

/* Global Reset / Base ------------------------------------------------------ */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html {
  font-size: 100%;
}

body {
  margin: 0;
  padding: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-base);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-800);
  background-color: var(--color-primary-bg);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  display: block;
}

a {
  color: var(--color-primary-accent);
  text-decoration: none;
}

a:hover,
a:focus-visible {
  text-decoration: underline;
}

.page {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  background-color: var(--color-primary-bg);
}

.site-main {
  flex: 1 0 auto;
}

/* Header ------------------------------------------------------------------- */

.site-header {
  position: relative;
  z-index: 10;
  color: var(--color-primary-fg);
  background: linear-gradient(to bottom, rgba(11, 30, 74, 0.96), rgba(11, 30, 74, 0.82));
}

.site-header-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: var(--space-2) var(--space-2) var(--space-1);
  text-align: center;
}

/* Brand line at top center, echoing the design */

.brand-bar {
  font-family: var(--font-heading);
  font-size: 1.0625rem;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

.brand-name {
  color: var(--color-primary-fg);
  text-decoration: none;
}

.brand-name:hover,
.brand-name:focus-visible {
  text-decoration: none;
  opacity: 0.85;
}

.brand-divider {
  height: 1px;
  width: 100%;
  margin: var(--space-1) auto var(--space-2);
  background-color: rgba(255, 255, 255, 0.3);
}

/* Primary navigation: understated, centered row of links */

.primary-nav {
  overflow-x: auto;
}

.primary-nav::-webkit-scrollbar {
  height: 6px;
}

.primary-nav::-webkit-scrollbar-thumb {
  background-color: rgba(255, 255, 255, 0.3);
}

.primary-nav-list {
  list-style: none;
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-1) var(--space-2);
  padding: 0;
  margin: 0;
}

.primary-nav-item a {
  display: inline-block;
  padding-bottom: 4px;
  font-family: var(--font-body);
  font-size: 0.9375rem;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--color-primary-fg);
  border-bottom: 1px solid transparent;
  white-space: nowrap;
}

.primary-nav-item a:hover,
.primary-nav-item a:focus-visible {
  border-bottom-color: var(--color-primary-accent);
  text-decoration: none;
}

/* Footer ------------------------------------------------------------------- */

.site-footer {
  flex-shrink: 0;
  background-color: #111111;
  color: var(--color-primary-fg);
  padding: var(--space-4) var(--space-2) var(--space-3);
}

.site-footer-inner {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  text-align: center;
}

.footer-nav-list {
  list-style: none;
  padding: 0;
  margin: 0 0 var(--space-2);
  display: flex;
  flex-wrap: wrap;
  justify-content: center;
  gap: var(--space-1) var(--space-3);
}

.footer-nav-item a {
  font-size: 0.875rem;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--color-primary-fg);
}

.footer-nav-item a:hover,
.footer-nav-item a:focus-visible {
  color: var(--color-primary-accent);
  text-decoration: none;
}

.footer-meta {
  margin: 0;
  font-size: var(--font-size-small);
  color: rgba(255, 255, 255, 0.8);
  line-height: 1.6;
}

.footer-meta-line {
  display: block;
}

/* Typography helpers for content areas ------------------------------------ */

h1,
h2,
h3,
h4,
h5,
h6 {
  margin: 0 0 var(--space-2);
  font-family: var(--font-heading);
  font-weight: 700;
  line-height: var(--line-height-tight);
  color: var(--color-secondary-dark);
}

h1 {
  font-size: var(--font-size-h1);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin: 0 0 var(--space-2);
}

/* Classic section heading with red divider lines (for use in main content) */

.section-heading {
  position: relative;
  display: inline-block;
  margin: var(--space-5) auto var(--space-3);
  padding: 0 var(--space-3);
  font-family: var(--font-heading);
  font-size: var(--font-size-h2);
  font-weight: 700;
  color: var(--color-primary-accent);
  text-align: center;
}

.section-heading::before,
.section-heading::after {
  content: '';
  position: absolute;
  top: 50%;
  width: 9999px;
  height: 2px;
  background-color: var(--color-primary-accent);
}

.section-heading::before {
  right: 100%;
}

.section-heading::after {
  left: 100%;
}

/* Hero pattern (for pages that use a theatrical hero image) --------------- */

.hero {
  position: relative;
  min-height: 60vh;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: calc(var(--space-6) + 40px) var(--space-2) var(--space-5);
  text-align: center;
  color: var(--color-primary-fg);
  overflow: hidden;
}

.hero::before {
  content: '';
  position: absolute;
  inset: 0;
  background-position: center center;
  background-repeat: no-repeat;
  background-size: cover;
  /* Page-level styles can override this with an actual image. */
  background-color: #000000;
  opacity: 0.85;
}

.hero::after {
  /* Subtle vignette for drama */
  content: '';
  position: absolute;
  inset: 0;
  background: radial-gradient(circle at center, rgba(0, 0, 0, 0) 0%, rgba(0, 0, 0, 0.55) 70%);
}

.hero-inner {
  position: relative;
  z-index: 1;
  max-width: 720px;
}

.hero-title {
  margin-bottom: var(--space-3);
  font-family: var(--font-heading);
  font-size: clamp(2.5rem, 4vw, 4rem);
  font-weight: 700;
  line-height: 1.1;
}

.hero-subtitle {
  margin-bottom: var(--space-3);
  font-size: 1rem;
}

.hero-meta {
  font-size: 0.9375rem;
}

/* Layout helpers for inner content containers ----------------------------- */

.container {
  max-width: var(--layout-max-width);
  margin: 0 auto;
  padding: 0 var(--space-2);
}

.section {
  padding: var(--space-5) 0;
}

.section--light {
  background-color: var(--color-neutral-050);
}

.section--white {
  background-color: var(--color-neutral-000);
}

/* Responsive adjustments --------------------------------------------------- */

@media (max-width: 768px) {
  .site-header-inner {
    padding-inline: var(--space-1);
  }

  .primary-nav-list {
    flex-wrap: nowrap;
    justify-content: flex-start;
    gap: var(--space-1);
  }

  .primary-nav-item a {
    font-size: 0.8125rem;
  }

  .section-heading {
    font-size: 1.75rem;
    margin-top: var(--space-4);
  }

  .site-footer {
    padding-inline: var(--space-1);
  }
}

@media (min-width: 1024px) {
  .site-header-inner {
    padding-top: var(--space-3);
    padding-bottom: var(--space-2);
  }

  .primary-nav-item a {
    font-size: 0.9375rem;
  }
}
